// Timer Screen Components Contract
// Files: src/screens/TimerScreen.tsx, src/components/timer/TimerDisplay.tsx,
//        src/components/timer/TimerControls.tsx, src/components/timer/CategorySelector.tsx

// Import from '@/screens'
export function TimerScreen(): React.ReactElement;

// Import from '@/components/timer'
export interface TimerDisplayProps {
  style?: ViewStyle;
}
export function TimerDisplay(props: TimerDisplayProps): React.ReactElement;

export interface TimerControlsProps {
  onStart: () => void;
  onStop: () => void;
  isStarting?: boolean;
  isStopping?: boolean;
  disabled?: boolean;
  style?: ViewStyle;
}
export function TimerControls(props: TimerControlsProps): React.ReactElement;

export interface CategorySelectorProps {
  visible: boolean;
  onClose: () => void;
  onSelect: (categoryId: string | null) => void;
  selectedCategoryId?: string | null;
  style?: ViewStyle;
}
export function CategorySelector(props: CategorySelectorProps): React.ReactElement;

// Behavior notes:
// - TimerDisplay shows HH:MM:SS format, updates every second via useTimerStore
// - TimerDisplay shows 'No active timer' when idle with dimmed 00:00:00
// - TimerControls shows Start button when no timer, Stop button when active
// - CategorySelector is a modal showing user's categories with colors and types
// - CategorySelector allows 'No category' option at the top of the list
// - TimerScreen integrates useRealtimeTimer for multi-device sync
// - TimerScreen shows connection status indicator (connected/reconnecting/disconnected)
// - TimerScreen shows quick notes input when stopping timer
// - Responsive layout works on phone and tablet
